const inputData = $input.all()[0].json;

let formattedTranscript = '';

if (Array.isArray(inputData.transcript)) {
  formattedTranscript = inputData.transcript
    .map(entry => {
      const timestamp = entry.timestamp || '';
      const speaker = entry.owner || entry.speaker || entry.name || 'Unknown';
      const text = entry.text || entry.task || entry.content || '';

      if (timestamp && speaker && text) {
        return `[${timestamp}] ${speaker}: "${text}"`;
      } else if (text) {
        return text;
      }
      return '';
    })
    .filter(line => line.length > 0)
    .join('\n');
} else if (typeof inputData.transcript === 'string') {
  formattedTranscript = inputData.transcript;
} else {
  formattedTranscript = JSON.stringify(inputData.transcript, null, 2);
}

return [{
  json: {
    formattedTranscript: formattedTranscript,
    deal_id: inputData.deal_id,
    prospect_name: inputData.prospect_name,
    rep_name: inputData.rep_name,
    call_date: inputData.call_date,
    call_duration_minutes: inputData.call_duration_minutes
  }
}];

// 1. Get the raw AI string from the AI Agent node
const rawOutput = $node["AI Agent"].json["output"];

// 2. Clean the AI string (removing markdown code blocks)
const cleanString = rawOutput.replace(/```json\n|```/g, "");
let cleanedData = JSON.parse(cleanString);

// 3. Logic to fetch Meeting ID from the Webhook trigger
// We check multiple possible locations based on the Zoom event type
const webhookBody = $node["Webhook"].json["body"];
const eventType = webhookBody.event;

let meetingId = "";

if (eventType === "meeting.ended") {
  // Path for meeting.ended
  meetingId = webhookBody.payload.object.id;
} else if (eventType === "meeting.participant_joined" || eventType === "scheduler.scheduled_event_created") {
  // Path for scheduler or other events (Adjust "scheduler.created" path if it differs slightly)
  // Usually Zoom keeps it under payload.object.id or payload.object.meeting_id
  meetingId = webhookBody.payload.object.id || webhookBody.payload.object.meeting_id;
} else {
  // Fallback/Default if it's an unknown event
  meetingId = webhookBody.payload?.object?.id || "N/A";
}

// 4. Inject the meetingId into the cleaned data object
// This makes it available for your Google Sheets "Get" or "Insert" steps
cleanedData.meeting_id = meetingId;
cleanedData.event_type = eventType; // Optional: helpful for debugging

return cleanedData;

