// Get binary data and convert to text
const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const vttContent = binaryData.toString('utf8');

const lines = vttContent.split('\n');
const transcript = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();

  if (
    !line || 
    line === 'WEBVTT' || 
    line.includes('-->') || 
    /^\d+$/.test(line) ||
    line.startsWith('NOTE')
  ) {
    continue;
  }

  transcript.push(line);
}

return [{
  json: {
    transcript: transcript.join('\n'),
    recording_start: $('Get Zoom Transcript').item.json.recording_start,
    recording_end: $('Get Zoom Transcript').item.json.recording_end
  }
}];

const crypto = require('crypto');
const secretToken = 'mYvSk8u9RTagPm8E_iYMLw';
const body = $input.first().json.body || $input.first().json; // Fallback if body isn't nested
const event = body?.event;

// 1. Handle CRC validation challenge
if (event === 'endpoint.url_validation') {
  const plainToken = body?.payload?.plainToken;

  const encryptedToken = crypto
    .createHmac('sha256', secretToken)
    .update(plainToken)
    .digest('hex');

  return [{ 
    json: { 
      plainToken, 
      encryptedToken, 
      isValidation: true 
    } 
  }];
}

// 2. Handle Real Events
return [{ 
  json: { 
    ...body,
    isValidation: false,
    eventType: event // Dynamically captures 'scheduler.scheduled_event_created'
  } 
}];

const input = $input.first().json;

// Handle error from previous step (e.g. 404 recording not found)
if (input.error) {
  return [{ json: { error: 'No transcript found', reason: input.error.message || 'Previous step returned an error' } }];
}

const recordingFiles = input.recording_files;

// Handle missing or empty recording_files
if (!recordingFiles || !Array.isArray(recordingFiles)) {
  return [{ json: { error: 'No transcript found', reason: 'No recording files in response' } }];
}

// Find the transcript file
const transcriptFile = recordingFiles.find(f => f.file_type === 'TRANSCRIPT');
if (!transcriptFile) {
  return [{ json: { error: 'No transcript found', recording_files: recordingFiles } }];
}

return [{ 
  json: { 
    transcript_url: transcriptFile.download_url,
    recording_start: transcriptFile.recording_start,
    recording_end: transcriptFile.recording_end
  } 
}];

