return items.map(item => {
  // This tells n8n: "Use the body if it exists, otherwise use the whole item"
  const body = item.json.body || item.json; 
  const payload = body.payload || {};
  const obj = payload.object || {};
  const scheduledEvent = obj.scheduled_event || {};
  const externalLocation = scheduledEvent.external_location || {};
  const startTime = scheduledEvent.start_date_time || null;
  const endTime = scheduledEvent.end_date_time || null;

  const schedulerEventId = scheduledEvent.event_id || null;

  let duration = null;
  if (startTime && endTime) {
    duration = Math.round(
      (new Date(endTime).getTime() - new Date(startTime).getTime()) / 60000
    );
  }

  const inviteeName = [obj.invitee_first_name, obj.invitee_last_name]
    .filter(Boolean)
    .join(' ')
    .trim();

  const topic = inviteeName
    ? `${scheduledEvent.summary || 'Meeting'} - ${inviteeName}`
    : (scheduledEvent.summary || 'Meeting');

  const dynamicEvent = body.event || item.json.event || null;
  const dynamicEventType = body.eventType || item.json.eventType || dynamicEvent;

  const meetingId = externalLocation.meeting_id || null;

  return {
    json: {
      event: dynamicEvent,
      payload: {
        account_id: payload.account_id || null,
        object: {
          event_id: schedulerEventId, // ✅ Zoom Scheduler event_id
          duration,
          start_time: startTime,
          timezone: obj.time_zone || null,
          end_time: endTime,
          topic,
          id: meetingId,
          type: 2,
          uuid: meetingId,
          host_id: payload.user_id || null,
          invitee: {
            email: obj.invitee_email || null,
            first_name: obj.invitee_first_name || null,
            last_name: obj.invitee_last_name || null,
            full_name: inviteeName || null,
